 --- FIX FIELDS ON THE TABLE

 -- HOME > Visual Enterprise Financial Reports > FAS Depreciation
-- =============================================
-- Author: traci treffret
-- Create date : 7/30/2020
-- Description : Dataset for Fixed Asset Depreciation
-- Notes : 
--> special coding for recent additions, lump sum dep values

--> CHECK THESE DATES BASED UPON LIFE!!! [Depreciation Ending]        
--> CHECK THE [MONTHS]        

; WITH CTE_FA AS
(SELECT [Unique]
, [GL]
, [Location]
, [Reference No]
, [Description]
, [Acq Date]
, [Date IfDiff]
, [Cost Basis]
, [Additions]
, [Disposed]
, [Ending Cost]
, [Method]
, CASE
	WHEN DAY([Acq Date]) > 15 THEN DATEADD(MONTH, DATEDIFF(MONTH, 1, [Acq Date]), 0) 
	ELSE DATEADD(MONTH, 1, DATEADD(MONTH, DATEDIFF(MONTH, 0, [Acq Date]), 0))
END AS [Depreciation Start]
, CAST(ISNULL([Life], 0) AS INT) AS [Life]
, CAST(ISNULL([Life], 0) AS INT) * 12 AS [Months]
FROM FixedAssets
)
--SELECT * FROM CTE_FA 

SELECT [Unique]
, [GL]
, [Location]
, [Reference No]
, [Description]
, [Acq Date]
, [Date IfDiff]
, [Cost Basis]
, [Additions]
, [Disposed]
, [Ending Cost]
, [Method]
, [Life]
, CAST([Depreciation Start] AS DATE) AS [Depreciation Start]
, DATEADD(YEAR, ISNULL(CAST([LIFE] AS INT),0), CAST([Depreciation Start] AS DATE)) AS [Depreciation Ending]
, [Months]
INTO #T1
FROM CTE_FA 

SELECT * FROM #T1
SELECT * FROM FixedAssets 

